class Solution {
    public long maximumTripletValue(int[] nums) {
        long maxVal = 0;
        int maxK = Integer.MIN_VALUE;
        int minDiff = Integer.MIN_VALUE;

        for (int k = nums.length - 1; k >= 2; k--) {
            maxK = Math.max(maxK, nums[k]);
            long currMax = maxK * (nums[k - 2] - nums[k - 1]);
            maxVal = Math.max(maxVal, currMax);
            if (k > 2) {
                minDiff = Math.max(minDiff, nums[k - 2] - nums[k - 1]);
            }
            if (k < nums.length - 1) {
                currMax = maxK * minDiff;
                maxVal = Math.max(maxVal, currMax);
            }
        }
        return Math.max(maxVal, 0);
    }
}
